<?phpnamespace App\Helpers;use Illuminate\Support\Facades\Crypt;use Session;use DB;class InitHelp{    public static function dataTeknisi($role, $parameter)    {        $query = DB::table("pegawai as a")->leftJoin(            "role as z",            "a.id_role",            "=",            "z.role_id"        );        if ($parameter == 1) {            $query->select(                "role_nama",                "pgw_id",                "pgw_nama",                "pgw_nip",                "id_role",                "pgw_status",                "pgw_password"            );            $query->where("id_role", $role);            $query->where("pgw_status", "y");        } elseif ($parameter == 2) {            $query->select(                "role_nama",                "pgw_id",                "pgw_nama",                "pgw_nip",                "id_role",                "pgw_status",                "pgw_password",                DB::raw("COUNT(b.sanitasi_id) as total")            );            $query->leftJoin("sanitasi as b", function ($join) {                $join->on("a.pgw_id", "=", "b.id_pgw");            });            $query->groupBy(                "role_nama",                "a.pgw_id",                "a.pgw_nama",                "a.pgw_nip",                "a.id_role",                "a.pgw_status",                "pgw_password"            );        } else {        }        $query->orderBy("id_role", "asc");        $query->orderBy("pgw_nama", "asc");        $data = $query->get();        return $data;    }    public static function dataArea($parameter)    {        $query = DB::table("area");        if ($parameter == 1) {            $query->where("area_status", "y");        }        $query->orderBy("area_nama", "asc");        $data = $query->get();        return $data;    }    public static function cekDataArea($id)    {        $data = DB::table("sanitasi")            ->where("id_area", $id)            ->get();        return $data;    }    public static function cekNip($nip)    {        $data = DB::table("pegawai")            ->where("pgw_nip", $nip)            ->count();        return $data;    }	public static function dataAkses($id)    {        $data = DB::table("role")            ->where("role_status", "y")            ->get();        return $data;    }	    public static function dataRole()    {        $data = DB::table("role")            ->where("role_status", "y")            ->get();        return $data;    }		public static function roleData()    {        $data = DB::table("role")->get();        return $data;    }		public static function roleDataEdit($id)    {        $data = DB::table("role")				->where("role_id", $id)				->get();        return $data;    }    public static function cekArea($idPgw, $idArea)    {        $data = DB::table("pegawai_area")            ->where("id_pgw", $idPgw)            ->where("id_area", $idArea)            ->count();        return $data;    }    public static function cekDataPgw($id)    {        $hit = 0;        $data = DB::table("sanitasi")            ->where("id_pgw", $id)            ->count();        return $data;    }    public static function cekDataAktivitas($id)    {        $data = DB::table("sanitasi")            ->where("id_aktivitas", $id)            ->get();        return $data;    }    public static function dataAreaPegawai($id)    {        $data = DB::table("pegawai_area as a")            ->select("area_nama", "id_area")            ->leftJoin("pegawai as b", function ($join) {                $join                    ->on("a.id_pgw", "=", "b.pgw_id")                    ->where("b.pgw_status", "=", "y");            })            ->leftJoin("area as c", function ($join) {                $join                    ->on("a.id_area", "=", "c.area_id")                    ->where("c.area_status", "=", "y");            })            ->where("a.id_pgw", "=", $id)            ->get();        return $data;    }    public static function dataAreaPerPegawai($id)    {        $data = DB::table("area")            ->whereNotIn("area_id", function ($query) use ($id) {                $query                    ->select("id_area")                    ->from("pegawai_area")                    ->where("id_pgw", "=", $id);            })            ->get();        return $data;    }    public static function dataAreaTeknisi($id)    {        $data = DB::table("pegawai_area as a")            ->select("area_nama", "id_area", "pegawai_area_id")            ->leftJoin("area as b", "a.id_area", "=", "b.area_id")            ->where("a.id_pgw", "=", $id)            ->get();        return $data;    }    public static function dataAktivitas($parameter)    {        $query = DB::table("aktivitas");        if ($parameter == 1) {            $query->where("aktivitas_status", "y");        }        $query->orderBy("aktivitas_nama", "asc");        $data = $query->get();        return $data;    }    public static function dataBranding($tipe, $tipeAll, $parameter)    {        $query = DB::table("branding");        if ($parameter == 1) {            $query->where("branding_status", "y");            $query->where(function ($query) use ($tipe, $tipeAll) {                $query                    ->where("branding_tipe", $tipe)                    ->orWhere("branding_tipe", $tipeAll);            });        }        $query->orderBy("branding_nama", "asc");        $data = $query->get();        return $data;    }    public static function dataSparepart($tipe, $tipeAll, $parameter)    {        $query = DB::table("sparepart");        if ($parameter == 1) {            $query->where("sparepart_status", "y");            $query->where(function ($query) use ($tipe, $tipeAll) {                $query                    ->where("sparepart_tipe", $tipe)                    ->orWhere("sparepart_tipe", $tipeAll);            });        }        $query->orderBy("sparepart_nama", "asc");        $data = $query->get();        return $data;    }    public static function getNamaBulan($bulan)    {        switch ($bulan) {            case "01":                return "JANUARI";            case "02":                return "FEBRUARI";            case "03":                return "MARET";            case "04":                return "APRIL";            case "05":                return "MEI";            case "06":                return "JUNI";            case "07":                return "JULI";            case "08":                return "AGUSTUS";            case "09":                return "SEPTEMBER";            case "10":                return "OKTOBER";            case "11":                return "NOVEMBER";            case "12":                return "DESEMBER";            default:                return "-";        }    }    public static function getNamaHari($hari)    {        switch ($hari) {            case "1":                return "Senin";            case "2":                return "Selasa";            case "3":                return "Rabu";            case "4":                return "Kamis";            case "5":                return "Jumat";            case "6":                return "Sabtu";            case "7":                return "Minggu";            default:                return "-";        }    }    public static function formatAkuntansi($nilai)    {        // Cek jika nilai negatif        if ($nilai < 0) {            // Menghilangkan tanda minus dan menambahkan dalam tanda kurung            return "(" . number_format(abs($nilai), 2) . ")";        } else {            // Format normal jika nilai positif            return number_format($nilai, 2);        }    }    public static function GetTransID()    {        srand((float) microtime() * 1000000);        $r = rand();        $u = uniqid(getmypid() . $r . (float) microtime() * 1000000, 1);        $m = md5($u);        return $m;    }    public static function GetID($table, $primary)    {        $data = DB::table($table)            ->latest($primary)            ->first($primary);        $maxId = $data ? $data->$primary + 1 : 1;        return $maxId;    }    public static function GetIpAddress()    {        foreach (            [                "HTTP_CLIENT_IP",                "HTTP_X_FORWARDED_FOR",                "HTTP_X_FORWARDED",                "HTTP_X_CLUSTER_CLIENT_IP",                "HTTP_FORWARDED_FOR",                "HTTP_FORWARDED",                "REMOTE_ADDR",            ]            as $key        ) {            if (array_key_exists($key, $_SERVER) === true) {                foreach (explode(",", $_SERVER[$key]) as $ip) {                    $ip = trim($ip); // just to be safe                    if (                        filter_var(                            $ip,                            FILTER_VALIDATE_IP,                            FILTER_FLAG_NO_PRIV_RANGE | FILTER_FLAG_NO_RES_RANGE                        ) !== false                    ) {                        return $ip;                    }                }            }        }        return request()->ip(); // it will return server ip when no client ip found    }    public static function mimeToExtension($mime)    {        $map = [            "image/jpeg" => "jpg",            "image/pjpeg" => "jpg",            "image/png" => "png",            "image/gif" => "gif",            "image/webp" => "webp",        ];        return $map[$mime] ?? "jpg"; // default jpg kalau tidak dikenali    }    public static function LapTransaksi(        $field,        $tabel,        $jenis,        $primary,        $kriteria,        $search    ) {        $query = DB::table($tabel . " as a");        if ($jenis == 1) {            $query->leftJoin("pegawai as b", "a.id_pgw", "=", "b.pgw_id");            $query->leftJoin("area as c", "a.id_area", "=", "c.area_id");            $query->leftJoin(                "aktivitas as d",                "a.id_aktivitas",                "=",                "d.aktivitas_id"            );            if ($kriteria == 1) {                $query->whereRaw("UPPER(pgw_nama) LIKE UPPER(?)", [                    "%" . $search . "%",                ]);            } elseif ($kriteria == 2) {                $query->whereRaw("UPPER(outlet_nama) LIKE UPPER(?)", [                    "%" . $search . "%",                ]);            } elseif ($kriteria == 3) {                $query->whereRaw("UPPER(masalah_pelaporan) LIKE UPPER(?)", [                    "%" . $search . "%",                ]);            } elseif ($kriteria == 4) {                $query->whereRaw("UPPER(area_nama) LIKE UPPER(?)", [                    "%" . $search . "%",                ]);            } elseif ($kriteria == 5) {                $query->whereRaw("UPPER(aktivitas_nama) LIKE UPPER(?)", [                    "%" . $search . "%",                ]);            } else {            }        }        if ($jenis == 2) {            if ($kriteria == 1) {                $query->whereRaw("UPPER(teknisi_nama) LIKE UPPER(?)", [                    "%" . $search . "%",                ]);            } elseif ($kriteria == 2) {                $query->whereRaw("UPPER(outlet_nama) LIKE UPPER(?)", [                    "%" . $search . "%",                ]);            } elseif ($kriteria == 3) {                $query->whereRaw("UPPER(permasalahan_chiller) LIKE UPPER(?)", [                    "%" . $search . "%",                ]);            } else {            }        }        $query->orderBy($primary, "desc");        $data = $query->get();        return $data;    }    public static function LapTransaksiExcel($field,$tabel,$jenis,$id,$primary) {        $query = DB::table($tabel . " as a");        if (!empty($id) && $id !== 'ALL') {            //$ids = explode(',', $id);            $idArray = explode(",", $id);            $ids = array_map(function ($item) {                return Crypt::decrypt($item);            }, $idArray);            $query->whereIn($primary, $ids);        }        if ($jenis == 1) {            $query->leftJoin("pegawai as b", "a.id_pgw", "=", "b.pgw_id");            $query->leftJoin("area as c", "a.id_area", "=", "c.area_id");            $query->leftJoin("aktivitas as d", "a.id_aktivitas","=", "d.aktivitas_id");        }        $query->orderBy($primary, "desc");        $data = $query->get();		        return $data;    }    public static function dataFile($id)    {        $data = DB::table("files_service as a")            ->select("a.*", "b.service_when", "b.outlet_nama", "b.teknisi_nama")            ->leftJoin("service as b", "a.id_service", "=", "b.service_id")            ->where("id_service", $id)            ->orderBy("files_jenis", "asc")            ->get();        return $data;    }    // untuk update transaksi service    public static function dataInputService($param)    {        $data = DB::table("service")            ->where("service_id", Crypt::decrypt($param))            ->get();        return $data;    }    public static function dataInputSanitasi($param)    {        $data = DB::table("sanitasi as a")            ->leftJoin("pegawai as b", "a.id_pgw", "=", "b.pgw_id")            ->leftJoin("area as c", "a.id_area", "=", "c.area_id")            ->leftJoin(                "aktivitas as d",                "a.id_aktivitas",                "=",                "d.aktivitas_id"            )            ->where("sanitasi_id", Crypt::decrypt($param))            ->get();        return $data;    }    public static function dataImageBefore($param, $jenis)    {        $data = DB::table("files_service")            ->where("id_service", $param)            ->where("files_jenis", $jenis)            ->get();        return $data;    }    public static function dataImageAfter($param, $jenis)    {        $data = DB::table("files_service")            ->where("id_service", $param)            ->where("files_jenis", $jenis)            ->get();        return $data;    }}